--在协议数据处理完之后需要调用finish
function ModelFriend:OnModelRequest()
    self._friendData={}
    self._friendManageData={}
    self._winType=true
    self._popType2=true
    self._popType3=true
    self._friendWinList={}--好友列表
    self._friendPopTypeList={}--好友弹窗类型列表，1-查找列表，2-申请列表，3-黑名单
    self._timer = LxTimer:New()
    self:OnRelationIdReq()
    self:ModelFinish()
end
----------------------------监听协议--------------------------------------
function ModelFriend:OnRelationProcessResp(pb)--关系操作请求（好友请求/同意申请/拉黑玩家）
    local relationType = pb.relationType--关系类型（1.好友请求，2.好友，3.黑名单）
    local targetId = pb.targetId
    local type = pb.type--操作类型（1.创建，2.删除）
    local targetName=pb.targetName
    if(relationType==1)then
        if(type==1)then
            self._friendReqIds[targetId]=targetId
            GF.ShowMessage(string.replace(ccClientText(12049),targetName))
        else
            self._friendReqIds[targetId]=nil
        end
    elseif(relationType==2)then
        if(type==2)then
 			self:OnRelationListReq(2)--在删除界面立马刷新            GF.ShowMessage(ccClientText(12043))
            self._friendReqIds[targetId]=nil
        else
            self._bRelationReq=true--记个状态，好友界面再请求
            self._friendReqIds[targetId]=nil
            self:OnRelationListReq(2)--在同意申请界面立马刷新
			self:OnRelationListReq(1)--在同意申请界面立马刷新
            GF.ShowMessage(ccClientText(12050))
        end
    else
        if(type==1)then
            self._blackIds[targetId]=targetId
            self._friendReqIds[targetId]=nil
            self:OnRelationListReq(2)
            GF.ShowMessage(ccClientText(12048))
        else
            self._blackIds[targetId]=nil
            self:OnRelationListReq(3)--在黑名单申请界面立马刷新
            GF.ShowMessage(ccClientText(12042))
        end
    end
end

function ModelFriend:OnRelationListResp(pb)--关系列表请求返回
    local relationType=pb.relationType--关系类型（1.好友请求，2.好友，3.黑名单）
    local endPackage=pb.endPackage--分包标识，false，标识未下发结束，true标识下发结束是最后一个包
    local giftCount=pb.giftCount--目前已有爱心数量
    local giftPlayers=pb.giftPlayers--已送礼的玩家Id列表
    local getPlayers=pb.getPlayers--可领取爱心的的玩家Id列表
    local receivePlayers=pb.receivePlayers--已领取爱心的的玩家Id列表
    local players=pb.players
    if(relationType==1 and self._popType2)then
        self._friendPopTypeList[2]={}
        self._popType2=false
    elseif(relationType==2 and self._winType)then
        self._friendWinList={}
        self._winType=false
    elseif(relationType==3 and self._popType3)then
        self._friendPopTypeList[3]={}
        self._popType3=false
    end
    local data={}
    for i = 1, #players do
        local info=players[i]
        local playerInfo=StructPlayerInfo:New()
        playerInfo:CreateByPb(info)
        if(relationType==1)then
            table.insert(self._friendPopTypeList[2],playerInfo)
        elseif(relationType==2)then
            table.insert(self._friendWinList,playerInfo)
        elseif(relationType==3)then
            table.insert(self._friendPopTypeList[3],playerInfo)
        end
    end
    if(endPackage==1)then
        if(relationType==2)then
            self._giftCount = giftCount
            self._giftPlayerList = {}
            self._getPlayerList = {}
            self._receivePlayerList={}
            for i, v in ipairs(giftPlayers) do
                self._giftPlayerList[v] = v
            end
            for i, v in ipairs(getPlayers) do
                self._getPlayerList[v] = v
            end
            for i, v in ipairs(receivePlayers) do
                self._receivePlayerList[v] = v
            end
            self._friendIds={}
            for i, v in pairs(self._friendWinList) do
                self._friendIds[v._playerId]=v._playerId
                self._friendReqIds[v._playerId]=nil
            end
            FireEvent(EventNames.FRIEND_ADDORDEL)
            FireEvent(EventNames.FRIEND_WIN_UPDATE_END)
            self._winType=true
        else
            FireEvent(EventNames.FRIEND_POP_UPDATE_END)
            if(relationType==1)then
                self._popType2=true
            else
                self._popType3=true
            end
        end
    end
end

function ModelFriend:OnGiftProcessResp(pb)--爱心操作请求返回
    local type=pb.type--类型：1.单个领取，2单个赠送 ， 3一键领取和赠送
    local playerId=pb.playerId
    local giftCount=pb.loveCount
    local sendCount=pb.sendCount
    if(self._giftCount and giftCount)then
        self._giftCount = self._giftCount + giftCount
    end
    if(type==1)then
        self._receivePlayerList[playerId] = playerId
    elseif(type==2)then
        GF.ShowMessage(ccClientText(12053))
        self._giftPlayerList[playerId] = playerId
    elseif(type==3)then
        if(giftCount==0 and sendCount==0 )then
            GF.ShowMessage(ccClientText(12044))
            return
        elseif(giftCount>0 and sendCount>0 )then
            GF.ShowMessage(ccClientText(12045))
        elseif(giftCount==0 and sendCount>0 )then
            GF.ShowMessage(ccClientText(12046))
        elseif(giftCount>0 and sendCount==0 )then
            GF.ShowMessage(ccClientText(12047))
        end
        for i, v in pairs(self._friendWinList) do
            local playerID= v._playerId
            self._receivePlayerList[playerID] = playerID
        end
        for i, v in pairs(self._friendWinList) do
            local playerID= v._playerId
            self._giftPlayerList[playerID] = playerID
        end
    end
    FireEvent(EventNames.FRIEND_GIFT_PROCESS)
end

function ModelFriend:OnFriendGiftResp(pb)--收到爱心通知
    local playerId=pb.playerId
    local playerName=pb.playerName
    if(self._getPlayerList)then
        self._getPlayerList[playerId] = playerId
    end
    GF.ShowMessage(string.replace(ccClientText(12032),playerName))
end

function ModelFriend:OnRelationIdResp(pb)--获取玩家所有关系Id列表返回
    local playerId
    local friends=pb.friends
    self._friendIds={}--好友列表
    self._friendReqIds={}--好友请求列表
    self._blackIds={}--黑名单列表
    for i = 1, #friends do
        playerId=friends[i]
        self._friendIds[playerId]=playerId
    end
    local friendReqs=pb.friendReqs
    for i = 1, #friendReqs do
        playerId=friendReqs[i]
        self._friendReqIds[playerId]=playerId
    end
    local blacks=pb.blacks
    for i = 1, #blacks do
        playerId=blacks[i]
        self._blackIds[playerId]=playerId
    end
end

function ModelFriend:OnRecommendResp(pb)--推荐好友请求返回
    local data={}
    local players = pb.players
    --if(#players<=0)then
    --    GF.ShowMessage(ccClientText(12034))
    --end
    for i = 1, #players do
        local info=players[i]
        local playerInfo=StructPlayerInfo:New()
        playerInfo:CreateByPb(info)
        table.insert(data,playerInfo)
        --self._friendReqIds[playerInfo.playerId] = nil
