function ModelFriend:OnQuickOperalResp(pb)--一键操作好友申请返回
    local type=pb.type
    if(type==1)then
        self._bRelationReq=true--记个状态，好友界面再请求
    end
    self:OnRelationListReq(1)
end

function ModelFriend:OnRelationListChangeResp(pb)--关系列表变动通知
    local type=pb.type                  --关系类型（1.好友请求，2.好友）
    local changeType = pb.changeType    --变动类型类型（1.新增，2.删除）
    local playerId = pb.playerId        --变动玩家Id
    local playerName = pb.playerName    --变动玩家名称
    if(type==1)then
        self:OnRelationListReq(type)
        FireEvent(EventNames.FRIEND_APPLYFOR_UPDATE)
    elseif(type==2)then
        self:OnRelationIdReq()
        self._bRelationReq=true--记个状态，好友界面再请求
        if changeType == 1 then
            GF.ShowMessage(string.replace(ccClientText(12064),playerName))
        end
    elseif(type==3)then
        self:OnRelationIdReq()
    end

end
-------------------------------发送协议-----------------------------------
function ModelFriend:OnRelationProcessReq(relationType,playerId,targetId,type)--关系操作请求（好友请求/同意申请/拉黑玩家）
    local pb = LProtoHelper.CreateProto(LProtoIds.RelationProcessReq)
    pb.relationType=relationType
    pb.playerId=playerId
    pb.targetId=targetId
    pb.type=type
    SendMessage(pb,LProtoIds.RelationProcessReq)
end

function ModelFriend:OnRelationListReq(relationType)--关系列表请求
    if(relationType==2)then
        self._bRelationReq=false
    end
    local pb = LProtoHelper.CreateProto(LProtoIds.RelationListReq)
    pb.relationType=relationType
    SendMessage(pb,LProtoIds.RelationListReq)
end

function ModelFriend:OnGiftProcessReq(type,playerId,playerIds)--爱心操作请求
    local pb = LProtoHelper.CreateProto(LProtoIds.GiftProcessReq)
    pb.type = type--类型：1.单个领取，2单个赠送 ， 3一键领取和赠送
    if(playerId)then
        pb.playerId = playerId
    end
    pb.selfId = gModelPlayer:GetPlayerId()
    if playerIds then
        for i, v in ipairs(playerIds) do
            pb.playerIds:append(v)
        end
    end
    SendMessage(pb,LProtoIds.GiftProcessReq)
end

function ModelFriend:OnRelationIdReq()--获取玩家所有关系Id列表
    local pb = LProtoHelper.CreateProto(LProtoIds.RelationIdReq)
    SendMessage(pb,LProtoIds.RelationIdReq)
    self._friendIds={}--好友列表
    self._friendReqIds={}--好友请求列表
    self._blackIds={}--黑名单列表
end

function ModelFriend:OnRecommendReq(type,playerName,bBtn)--推荐好友请求
    local pb = LProtoHelper.CreateProto(LProtoIds.RecommendReq)
    pb.type=type
    if(playerName)then
        pb.playerName=playerName
    elseif(bBtn)then
        if(not self._timeRecommend or self._timeRecommend==0)then
            self._timeRecommend = self:GetFindRecommendTime()
            if(self._timeRecommend>0)then
                local key = "RecommendReq"
                self._timer:TimerCreate(key, function(...) self:OnNextDayZero(...) end, 1, false, 1)
            end
        else
            GF.ShowMessage(string.replace(ccClientText(12038),self._timeRecommend))
            return
        end
        GF.ShowMessage(ccClientText(12039))
    end
    SendMessage(pb,LProtoIds.RecommendReq)
end

function ModelFriend:OnNextDayZero(key)
    self._timer:TimerRemoveByKey(key)
    self._timeRecommend=self._timeRecommend-1
    if(self._timeRecommend>0)then
        self._timer:TimerCreate(key, function(...) self:OnNextDayZero(...) end, 1, false, 1)
    end
end

function ModelFriend:OnQuickOperalReq(type)--一键操作好友申请
    local pb = LProtoHelper.CreateProto(LProtoIds.QuickOperalReq)
    pb.type=type
    SendMessage(pb,LProtoIds.QuickOperalReq)
end

function ModelFriend:OnBRelatioListnReq()--判断是否需要请求好友
    if(self._bRelationReq)then
        self:OnRelationListReq(2)
        self._bRelationReq=false
    end
end
----------------------------获取数据--------------------------------------
function ModelFriend:GetFeiendList()
    return self._friendWinList or {}
end

function ModelFriend:GetFeiendKeyList()
    local list = self:GetFeiendList()
    local fList = {}
    for i, v in ipairs(list) do
        fList[v._playerId] = v
    end
    return fList
end

function ModelFriend:GetFriendData()--获取好友数据
    local list = self:GetFeiendList()
    table.sort(list,function (a,b)
        local atime=tonumber(a._lastLogoutTime)
        local btime=tonumber(b._lastLogoutTime)
        if(a._playerState~=b._playerState )then
            return a._playerState>b._playerState
        end
        if(atime~=btime )then
            return atime>btime
        end
        return false
    end)
    return list
end

function ModelFriend:GetDelFriendData()
    local list = self:GetFeiendList()
    table.sort(list,function (a,b)
        local atime = tonumber(a._lastLogoutTime)
        local btime = tonumber(b._lastLogoutTime)
        if(atime ~= btime )then
            return atime < btime
        end
        return false
    end)
    return list
end

function ModelFriend:GetFriendNum()--获取现有好友数量
    local list=self._friendWinList or {}
    return #list
end

function ModelFriend:GetBGift(playerId)--是否已送礼的玩家
    local list = self:GetGiftPlayerList()
    return list[playerId] and true or false
end
function ModelFriend:GetBGet(playerId)--是否可领取爱心的玩家
    local list = self._getPlayerList or {}
    return list[playerId] and true or false
end
function ModelFriend:GetBReceive(playerId)--是否已领取爱心的玩家
    local list = self:GetReceiveList()
    return list[playerId] and true or false
end

function ModelFriend:GetFriendPopListByType(type)--根据类型获取好友管理数据，1-查找2-申请，3黑名单
    local list= self._friendPopTypeList[type] or {}
    return list
end

function ModelFriend:GetFriendship()--获取友情点
    return self._giftCount or 0
end

function ModelFriend:GetPlayerList()--可领取爱心的的玩家Id列表
    return  self._getPlayerList or {}
end
function ModelFriend:GetReceiveList()--已领取爱心的的玩家Id列表
    return self._receivePlayerList or {}
end

function ModelFriend:GetGetPlayerNum()--已领取人数
    local num = 0
    local list = self:GetReceiveList()
    for i, v in pairs(list) do
        num = num + 1
    end
    return num
end

function ModelFriend:GetGiftPlayerList()--已赠送人列表
    return self._giftPlayerList or {}
end

function ModelFriend:GetGiftPlayerNum()--已赠送人数
    local num = 0
    local list = self:GetGiftPlayerList()
    for i, v in pairs(list) do
        num = num + 1
    end
    return num
end

function ModelFriend:GetIsOnGift()--是否可赠送
    local num = self:GetGiftPlayerNum()
    local giftEx = self:GetFindSendLoveNum()
    return giftEx > num
end

function ModelFriend:GetIsOnGet()--是否可领取
    local num = self:GetGetPlayerNum()
    local getEx = self:GetFindReceiveLoveNum()
    return getEx > num
end

function ModelFriend:GetBFriend(playerId)--获取是否好友
    local playerId=self._friendIds[playerId]
    if(not playerId or playerId=="")then
        return false
    end
    return true
end

function ModelFriend:GetBAddHei(playerId)--获取是否在黑名单
    local _blackIds = self._blackIds
    if not _blackIds then
        return false
    end
    local playerId = _blackIds[playerId]
    if(not playerId or playerId=="")then
        return false
    end
    return true
end

function ModelFriend:GetRelationIdByType(type,playerId)--根据类型获取关系Id列表，1-好友 2-请求过 3-黑名单
    local id=nil
    if(type==1)then
        id= self._friendIds[playerId]--好友列表
    elseif(type==2)then
        id=self._friendReqIds[playerId]--好友请求列表
    else
        id=self._blackIds[playerId]--黑名单列表
    end
    return id
end

function ModelFriend:GetBlackBAdd()--获取黑名单是否能加
    local b=false
    local limit=self:GetblacklistLimit()
    if(limit and limit> #self._blackIds)then
        b=true
    end
    return b
end

function ModelFriend:GetSevenName(id)
    return gLGameLogin:GetServerShotNameById(id)
end

function ModelFriend:SetReqIdsList()
    self._oldReqIds = self._friendReqIds
    FireEvent(EventNames.FRIEND_APPLYFOR_UPDATE)
end

function ModelFriend:GetReqIdsList()--获取是否有申请列表
    if(not self._oldReqIds)then
        self._oldReqIds = {}
    end
    if(not self._friendReqIds)then
        self._friendReqIds = {}
    end
    if(#self._oldReqIds ~= #self._friendReqIds)then
        return true
    end
    for i, v in pairs(self._friendReqIds) do
        if(v ~= self._oldReqIds[i])then
            return true
        end
    end
    return false
end

function ModelFriend:GetOneKeyRed()
    local list = self:GetFriendData()
    for i, v in ipairs(list) do
        if(self:GetBGet(v._playerId))then
            return true
        end
        if(not self:GetBGift(v._playerId))then
            return true
        end
    end
    return false
end

function ModelFriend:GetLastLogoutTime(playerData)
    local timeStr = ""
    if(playerData._playerState == 1)then
        timeStr = ccClientText(12008)
    else
        timeStr = self:GetStateTime(playerData._lastLogoutTime)
    end
    return timeStr
end

function ModelFriend:GetStateTime(_lastLogoutTime)
    if not _lastLogoutTime then
        return ""
    end
    local time=GetTimestamp()
    local timespan = time - _lastLogoutTime/1000
    local timeTextStr = ""
    if timespan < 60 then
        timeTextStr = ccClientText(10366)
    else
        local day = self:GetFriendConfigRefByKey("offlineLimit")
        timeTextStr = string.replace(ccClientText(12561),LUtil.FormatTimeToMin(timespan,day))
    end
    return timeTextStr
end
